all(require(\"vue\"), false)\n  if (!hotAPI.compatible) return\n  module.hot.accept()\n  if (!module.hot.data) {\n    hotAPI.createRecord(\"data-v-ed0879dc\", Component.options)\n  } else {\n    hotAPI.reload(\"data-v-ed0879dc\", Component.options)\n  }\n  module.hot.dispose(function (data) {\n    disposed = true\n  })\n})()}\n\nmodule.exports = Component.exports\n\n\n\n//////////////////\n// WEBPACK FOOTER\n// ./modules/Internet/Resources/assets/js/view/pos/partials/service_form.vue\n// module id = ./modules/Internet/Resources/assets/js/view/pos/partials/service_form.vue\n// module chunks = 149","<template>\r\n    <div class=\"card bg-ligth\" v-loading=\"loading\">\r\n        <div class=\"row mt-2\">\r\n            <div class=\"col-12\">\r\n                <label class=\"label-control w-100\">Plan Actual</label>\r\n                <el-input :readonly=\"true\" :value=\"plan.name\"> </el-input>\r\n                <label v-if=\"paymentDay\" class=\"mt-2 label-control\"\r\n                    >Vencimiento:\r\n                    <strong>\r\n                        {{ `${paymentDay.split(\"/\")[0]} de cada mes` }}</strong\r\n                    ></label\r\n                >\r\n                <label\r\n                    v-if=\"currentPlan && currentPlan.days_extension != 0\"\r\n                    class=\"text-primary\"\r\n                    style=\"font-weight:bold\"\r\n                >\r\n                    / Prorroga:\r\n                    <strong> {{ currentPlan.days_extension }} días </strong>\r\n                </label>\r\n            </div>\r\n        </div>\r\n        <template v-if=\"updatePlan\">\r\n            <div class=\"row mt-2\">\r\n                <div class=\"col-md-6\">\r\n                    <label for=\"document type\">Plan nuevo</label>\r\n                    <el-select v-model=\"form.plan_id\" @change=\"changePrice\">\r\n                        <el-option\r\n                            v-for=\"(data, idx) in plans\"\r\n                            :key=\"idx\"\r\n                            :label=\"data.capacity\"\r\n                            :value=\"data.id\"\r\n                        >\r\n                        </el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-md-6\">\r\n                    <label for=\"document type\">Precio</label>\r\n                    <el-select\r\n                        v-model=\"variationId\"\r\n                        @change=\"updateNewPlanCost\"\r\n                    >\r\n                        <el-option\r\n                            v-for=\"(data, idx) in planVariations\"\r\n                            :key=\"idx\"\r\n                            :label=\"`${data.description} S/.${data.price}`\"\r\n                            :value=\"data.id\"\r\n                        >\r\n                        </el-option>\r\n                    </el-select>\r\n                </div>\r\n            </div>\r\n            <div class=\"row mt-2\">\r\n                <div class=\"col-md-5\">\r\n                    <label for=\"document type\">Extras/Conceptos</label>\r\n                    <el-select v-model=\"concept.id\" @change=\"changeConcept\">\r\n                        <el-option\r\n                            v-for=\"(data, idx) in concepts\"\r\n                            :key=\"idx\"\r\n                            :label=\"data.description\"\r\n                            :value=\"data.id\"\r\n                        >\r\n                        </el-option>\r\n                    </el-select>\r\n                </div>\r\n\r\n                <div class=\"col-md-5\">\r\n                    <label for=\"document type\">Precio</label>\r\n                    <el-select v-model=\"variationConceptId\">\r\n                        <el-option\r\n                            v-for=\"(data, idx) in conceptVariations\"\r\n                            :key=\"idx\"\r\n                            :label=\"`${data.description} S/.${data.price}`\"\r\n                            :value=\"data.id\"\r\n                        >\r\n                        </el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-md-2 mt-sm-2  mb-sm-1 d-flex align-items-end\">\r\n                    <el-button\r\n                        size=\"mini\"\r\n                        type=\"primary\"\r\n                        icon=\"el-icon-plus\"\r\n                        circle\r\n                        @click=\"addConcept\"\r\n                    ></el-button>\r\n                </div>\r\n                <div\r\n                    class=\"col-md-12 mt-1 table-responsive\"\r\n                    v-if=\"conceptsSelected.length != 0\"\r\n                >\r\n                    <table class=\"table  table-striped table-hover\">\r\n                        <thead>\r\n                            <tr>\r\n                                <th>#</th>\r\n                                <th>Extra</th>\r\n                                <th>Descripción</th>\r\n                                <th>Total</th>\r\n                                <th></th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>\r\n                            <tr\r\n                                v-for=\"(concept, idx) in conceptsSelected\"\r\n                                :key=\"idx\"\r\n                            >\r\n                                <td>{{ idx + 1 }}</td>\r\n                                <td>\r\n                                    {{ concept.generalConcept }}\r\n                                </td>\r\n                                <td>\r\n                                    {{ concept.description }}\r\n                                </td>\r\n                                <td>{{ concept.price }}</td>\r\n                                <td>\r\n                                    <el-button\r\n                                        @click=\"removeConcept(idx)\"\r\n                                        type=\"danger\"\r\n                                        icon=\"el-icon-delete\"\r\n                                        circle\r\n                                    ></el-button>\r\n                                </td>\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n                </div>\r\n            </div>\r\n        </template>\r\n        <template v-else>\r\n            <div class=\"row mt-1 \">\r\n                <el-checkbox-group\r\n                    v-model=\"monthsToPay\"\r\n                    disabled\r\n                    class=\" d-flex flex-wrap justify-content-center\"\r\n                    @change=\"payMonth\"\r\n                >\r\n                    <el-checkbox-button\r\n                        class=\"mt-1\"\r\n                        :class=\"m.isNew ? 'customcheck' : ''\"\r\n                        v-for=\"(m, idx) in monthsPayed\"\r\n                        :key=\"idx\"\r\n                        :label=\"m.start_date\"\r\n                        >{{\r\n                            `${formatDate(m.start_date)} - ${formatDate(\r\n                                m.end_date\r\n                            )}`\r\n                        }}</el-checkbox-button\r\n                    >\r\n                </el-checkbox-group>\r\n            </div>\r\n            <div class=\" mt-1 d-flex justify-content-center\">\r\n                <el-button-group>\r\n                    <el-button\r\n                        type=\"primary\"\r\n                        icon=\"el-icon-circle-plus\r\n\"\r\n                        @click=\"addPayment\"\r\n                        >Agregar pago</el-button\r\n                    >\r\n                    <el-button type=\"danger\" @click=\"removePayment\"\r\n                        >Retirar Pago\r\n                        <i class=\"el-icon-delete el-icon-right\"></i\r\n                    ></el-button>\r\n                </el-button-group>\r\n            </div>\r\n        </template>\r\n    </div>\r\n</template>\r\n<style>\r\n.customcheck {\r\n    background-color: #67c23a !important;\r\n    border-color: #e1f3d8 !important;\r\n}\r\n.customcheck span {\r\n    background-color: #67c23a !important;\r\n    color: #ffffff !important;\r\n}\r\n</style>\r\n<script>\r\nimport moment from \"moment\";\r\nexport default {\r\n    props: [\"registerId\", \"plan\", \"updatePlan\"],\r\n\r\n    data() {\r\n        return {\r\n            payments: [],\r\n            passedDays: 0,\r\n            leftDays: 0,\r\n            conceptsSelected: [],\r\n            newPlanCost: 0,\r\n            concept: {},\r\n            planVariations: [],\r\n            conceptVariations: [],\r\n            variationId: null,\r\n            variationConceptId: null,\r\n            plans: [],\r\n            concepts: [],\r\n            items: [],\r\n            techs: [],\r\n            serviceItem: null,\r\n            dataReconnection: null,\r\n            originalMonthsPayed: [],\r\n            monthsPayed: [],\r\n            monthsToPay: [],\r\n            resource: \"registers\",\r\n            loading: false,\r\n            plans: [],\r\n            date: moment(),\r\n            paymentDay: null,\r\n            form: {},\r\n            currentPlan: null,\r\n            penalties: [],\r\n            limitDate: null,\r\n            selectedMonths: [],\r\n            months: [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ]\r\n        };\r\n    },\r\n    async created() {\r\n        // await this.getTables();\r\n    },\r\n    methods: {\r\n        removeConcept(idx) {\r\n            this.conceptsSelected.splice(idx, 1);\r\n            this.updateNewPlanCost();\r\n        },\r\n        updateNewPlanCost() {\r\n            let [variation] = this.planVariations.filter(\r\n                p => p.id == this.variationId\r\n            );\r\n            this.newPlanCost = Number(variation.price);\r\n            if (this.conceptsSelected.length > 0) {\r\n                this.conceptsSelected.forEach(c => {\r\n                    this.newPlanCost += Number(c.price);\r\n                });\r\n            }\r\n\r\n            this.updateTotal();\r\n        },\r\n        observationChange() {\r\n            let [toPay] = this.calculateRestPlan();\r\n            let observation = `CAMBIO DE PLAN: ${toPay} RESTA PAGAR DEL PLAN ANTERIOR\\n`;\r\n            return observation;\r\n        },\r\n        changeConcept() {\r\n            let [concept] = this.concepts.filter(p => p.id == this.concept.id);\r\n\r\n            this.conceptVariations = concept.variations;\r\n\r\n            if (this.conceptVariations.length != 0) {\r\n                this.variationConceptId = this.conceptVariations[0].id;\r\n            } else {\r\n                this.variationConceptId = null;\r\n            }\r\n        },\r\n        addConcept() {\r\n            let [concept] = this.conceptVariations.filter(\r\n                cv => cv.id == this.variationConceptId\r\n            );\r\n\r\n            if (concept) {\r\n                let { concept_id } = concept;\r\n                let { description } = this.concepts.find(\r\n                    c => c.id == concept_id\r\n                );\r\n                this.conceptsSelected = this.conceptsSelected.filter(\r\n                    i => i.concept_id != concept.id\r\n                );\r\n                this.conceptsSelected.push({\r\n                    ...concept,\r\n                    generalConcept: description\r\n                });\r\n            }\r\n            this.updateNewPlanCost();\r\n        },\r\n        changePrice() {\r\n            let [plan] = this.plans.filter(p => p.id == this.form.plan_id);\r\n\r\n            this.form.plan_price = plan.default_price;\r\n            this.planVariations = plan.variations;\r\n\r\n            if (this.planVariations.length != 0) {\r\n                this.variationId = this.planVariations[0].id;\r\n            } else {\r\n                this.variationId = null;\r\n            }\r\n            if (this.variationId) {\r\n                this.updateNewPlanCost();\r\n            }\r\n            // this.calculateTotal();\r\n        },\r\n        addPayment() {\r\n            let end_date;\r\n            let amount;\r\n            let monthsNew = [];\r\n            if (this.monthsPayed.length == 0) {\r\n                end_date = this.plan.install_date;\r\n                amount = this.plan.total;\r\n            } else {\r\n                let lastPayment = this.monthsPayed[this.monthsPayed.length - 1];\r\n                monthsNew = this.monthsPayed.filter(m => m.isNew);\r\n                amount = lastPayment.amount;\r\n                if (this.dataReconnection && monthsNew.length == 0) {\r\n                    end_date = this.dataReconnection;\r\n                } else {\r\n                    end_date = lastPayment.end_date;\r\n                }\r\n            }\r\n\r\n            let newEndDate = moment(end_date).add(1, \"month\");\r\n\r\n            if (\r\n                monthsNew.length != 0 &&\r\n                this.originalMonthsPayed.length == 12\r\n            ) {\r\n                this.monthsPayed = this.originalMonthsPayed.slice(\r\n                    monthsNew.length + 1\r\n                );\r\n            }\r\n\r\n            this.monthsPayed = [\r\n                ...this.monthsPayed.filter(m => !m.isNew),\r\n                ...monthsNew\r\n            ];\r\n            this.monthsPayed = [\r\n                ...this.monthsPayed,\r\n                {\r\n                    amount,\r\n                    start_date: end_date,\r\n                    end_date: newEndDate,\r\n                    isNew: true\r\n                }\r\n            ];\r\n            this.monthsToPay.push(end_date);\r\n\r\n            this.checkMonths();\r\n            this.updateTotal();\r\n        },\r\n        changeInitialDate(date) {\r\n            this.dataReconnection = date;\r\n        },\r\n        checkForIncomplete() {\r\n            let observation = \"\";\r\n            let incomplete = this.originalMonthsPayed.find(\r\n                m => m.state == \"incomplete\"\r\n            );\r\n            if (this.originalMonthsPayed.length == 0 && incomplete == null) {\r\n                let payment = this.payments[this.payments.length - 1];\r\n                if (payment.type == \"incomplete\") {\r\n                    incomplete = {};\r\n                    incomplete.rest = payment.rest;\r\n                    incomplete.start_date = this.plan.install_date;\r\n                    incomplete.end_date = this.plan.install_date;\r\n                }\r\n            }\r\n            if (incomplete) {\r\n                if (incomplete.start_date == incomplete.end_date) {\r\n                    observation = `Saldo pendiente de la instalacion ${moment(\r\n                        incomplete.start_date\r\n                    ).format(\"DD/MM/YYYY\")}\\n`;\r\n                } else {\r\n                    observation = `Saldo pendiente del periodo ${moment(\r\n                        incomplete.start_date\r\n                    ).format(\"DD/MM/YYYY\")} - ${moment(\r\n                        incomplete.end_date\r\n                    ).format(\"DD/MM/YYYY\")}\\n`;\r\n                }\r\n            }\r\n            return observation;\r\n        },\r\n        checkMonths() {\r\n            let observation = this.checkForIncomplete();\r\n            if (this.monthsToPay.length == 1) {\r\n                let month = moment(this.monthsToPay[0]).format(\"DD/MM/YYYY\");\r\n                let nextMonth = moment(this.monthsToPay[0])\r\n                    .add(1, \"month\")\r\n                    .format(\"DD/MM/YYYY\");\r\n                observation += `Mensualidad de ${month} a ${nextMonth}`;\r\n            } else if (this.monthsToPay.length == 0) {\r\n                observation = \"\";\r\n            } else {\r\n                let month = moment(this.monthsToPay[0]).format(\"DD/MM/YYYY\");\r\n                let nextMonth = moment(\r\n                    this.monthsToPay[this.monthsToPay.length - 1]\r\n                )\r\n                    .add(1, \"month\")\r\n                    .format(\"DD/MM/YYYY\");\r\n                observation += `Mensualidad de ${month} a ${nextMonth}`;\r\n            }\r\n            observation = observation.toUpperCase();\r\n            this.$emit(\"updateObservation\", observation);\r\n        },\r\n        removePayment() {\r\n            let hasNew = this.monthsPayed.some(m => m.isNew);\r\n            if (hasNew) {\r\n                let lastNew = this.monthsPayed.pop();\r\n                let monthsNew = this.monthsPayed.filter(m => m.isNew);\r\n                if (\r\n                    monthsNew.length != 0 &&\r\n                    this.originalMonthsPayed.length == 12\r\n                ) {\r\n                    this.monthsPayed = this.originalMonthsPayed.slice(\r\n                        monthsNew.length\r\n                    );\r\n                }\r\n\r\n                this.monthsPayed = [\r\n                    ...this.monthsPayed.filter(m => !m.isNew),\r\n                    ...monthsNew\r\n                ];\r\n\r\n                this.monthsToPay = this.monthsToPay.filter(\r\n                    m => m != lastNew.start_date\r\n                );\r\n\r\n                this.checkMonths();\r\n                this.updateTotal();\r\n\r\n                if (monthsNew.length == 0) {\r\n                    this.setIncompleteObservation();\r\n                }\r\n            }\r\n        },\r\n        formatDate(date) {\r\n            return moment(date).format(\"DD/MM/YYYY\");\r\n        },\r\n\r\n        payMonth(x) {},\r\n        changePlan() {\r\n            this.paymentDay = null;\r\n            this.penalties = [];\r\n            this.currentPlan = null;\r\n            this.limitDate = null;\r\n            this.selectedMonths = [];\r\n            this.updateTotal();\r\n        },\r\n        //limit  es una fecha, con el mes y año actual, pero con el día del pago\r\n        //date es la fecha actual\r\n        //paymentday es solo el día\r\n        //\r\n        checkPenalty(date) {\r\n            let { total, penalty, days_extension } = this.currentPlan;\r\n\r\n            date = date.add(days_extension, \"days\");\r\n            if (this.date.isAfter(date.add())) {\r\n                if (penalty) {\r\n                    let { percentage, type } = penalty;\r\n                    percentage =\r\n                        type == \"percentage\"\r\n                            ? Number(percentage) / 100\r\n                            : Number(percentage);\r\n                    let totalPerDay =\r\n                        type == \"percentage\" ? total * percentage : percentage;\r\n                    let days = this.date.diff(date, \"days\");\r\n                    let month = date.get(\"month\") + 1;\r\n                    let nameMonth = this.months.find(m => m.id == month).label;\r\n                    this.penalties.push({\r\n                        id: month,\r\n                        days,\r\n                        label: nameMonth,\r\n                        penalty: days * totalPerDay\r\n                    });\r\n                }\r\n            }\r\n        },\r\n        selectMonth() {\r\n            this.updateTotal();\r\n        },\r\n        initForm() {\r\n            this.currentPlan = null;\r\n            this.penalties = [];\r\n            this.paymentDay = null;\r\n            this.form = {};\r\n            this.months = [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ];\r\n        },\r\n        typeParent(type) {\r\n            let types = {\r\n                mother: \"Madre:\",\r\n                father: \"Padre:\",\r\n                attorney: \"Apoderado:\"\r\n            };\r\n\r\n            return types[type];\r\n        },\r\n        setPaymentMonths(months, payments = []) {\r\n            this.originalMonthsPayed = months.reverse();\r\n            this.payments = payments;\r\n            this.monthsPayed = [...this.originalMonthsPayed];\r\n        },\r\n        async setMonths() {\r\n            this.months = [\r\n                { id: 1, label: \"Enero\", disabled: false },\r\n                { id: 2, label: \"Febrero\", disabled: false },\r\n                { id: 3, label: \"Marzo\", disabled: false },\r\n                { id: 4, label: \"Abril\", disabled: false },\r\n                { id: 5, label: \"Mayo\", disabled: false },\r\n                { id: 6, label: \"Junio\", disabled: false },\r\n                { id: 7, label: \"Julio\", disabled: false },\r\n                { id: 8, label: \"Agosto\", disabled: false },\r\n                { id: 9, label: \"Setiembre\", disabled: false },\r\n                { id: 10, label: \"Octubre\", disabled: false },\r\n                { id: 11, label: \"Noviembre\", disabled: false },\r\n                { id: 12, label: \"Diciembre\", disabled: false }\r\n            ];\r\n            let today = moment();\r\n            let installDate = moment(this.plan.install_date);\r\n\r\n            if (today.year() == installDate.year()) {\r\n                let month = installDate.month() + 1;\r\n                this.months = this.months.map(m => {\r\n                    if (m.id < month) {\r\n                        m.disabled = true;\r\n                    }\r\n                    return m;\r\n                });\r\n            }\r\n            let payments = this.plan.payments;\r\n            let paidmonths = [];\r\n            if (payments) {\r\n                for (let i = 0; i < payments.length; i++) {\r\n                    const payment = payments[i];\r\n                    if (payment.type == \"complete\") {\r\n                        paidmonths = [\r\n                            ...paidmonths,\r\n                            ...payment.months\r\n                                .filter(m => {\r\n                                    let dt = moment(m.year);\r\n                                    if (today.year() == dt.year()) {\r\n                                        return m;\r\n                                    }\r\n                                })\r\n                                .map(m => m.month)\r\n                        ];\r\n                    } else {\r\n                    }\r\n                }\r\n            }\r\n\r\n            for (let m of paidmonths) {\r\n                let month = this.months.find(mth => mth.id == m);\r\n                if (month) {\r\n                    month.disabled = true;\r\n                }\r\n            }\r\n        },\r\n        deepCopy(obj) {\r\n            if (obj === null || typeof obj !== \"object\") {\r\n                return obj;\r\n            }\r\n\r\n            let copy;\r\n\r\n            if (obj instanceof Array) {\r\n                copy = [];\r\n                for (let i = 0; i < obj.length; i++) {\r\n                    copy[i] = this.deepCopy(obj[i]);\r\n                }\r\n            } else {\r\n                copy = {};\r\n                for (let key in obj) {\r\n                    if (obj.hasOwnProperty(key)) {\r\n                        copy[key] = this.deepCopy(obj[key]);\r\n                    }\r\n                }\r\n            }\r\n\r\n            return copy;\r\n        },\r\n        calculateRestPlan() {\r\n            let total = this.plan.total;\r\n            let month = this.originalMonthsPayed[\r\n                this.originalMonthsPayed.length - 1\r\n            ];\r\n            let today = moment().startOf(\"day\");\r\n            let endDate = moment(month.end_date).startOf(\"day\");\r\n            let startDate = moment(month.start_date).startOf(\"day\");\r\n            let passed_days = endDate.diff(startDate, \"days\");\r\n            let left_days = endDate.diff(today, \"days\"); // devuelve 1\r\n\r\n            let totalPerDay = total / passed_days;\r\n            let toPay = totalPerDay * (passed_days - left_days);\r\n\r\n            return [toPay, left_days, passed_days];\r\n        },\r\n        async updateTotal(localItem) {\r\n            let items = [];\r\n\r\n            if (this.monthsToPay.length > 0) {\r\n                let plan = this.deepCopy(this.plan);\r\n                let { item, name, total } = plan;\r\n                item.sale_unit_price = total * this.monthsToPay.length;\r\n                item.percentage_igv = 18;\r\n                item.descriptionInternet = name;\r\n                items.push(item);\r\n            }\r\n            let incomplete = this.originalMonthsPayed.find(\r\n                m => m.state == \"incomplete\"\r\n            );\r\n            if (this.originalMonthsPayed.length == 0 && incomplete == null) {\r\n                let payment = this.payments[this.payments.length - 1];\r\n                if (payment.type == \"incomplete\") {\r\n                    incomplete = {};\r\n                    incomplete.rest = payment.rest;\r\n                    incomplete.start_date = this.plan.install_date;\r\n                    incomplete.end_date = this.plan.install_date;\r\n                }\r\n            }\r\n            if (this.updatePlan) {\r\n                let [toPay, left_days, passed_days] = this.calculateRestPlan();\r\n                this.leftDays = left_days;\r\n                this.passedDays = passed_days;\r\n                let plan = this.deepCopy(this.plan);\r\n                let { item, name } = plan;\r\n                item.sale_unit_price = toPay;\r\n                item.percentage_igv = 18;\r\n                item.descriptionInternet = name + \" (Saldo plan anterior)\";\r\n                items.push(item);\r\n                let observation = `CAMBIO DE PLAN: ${toPay} RESTA PAGAR DEL PLAN ANTERIOR`;\r\n                this.$emit(\"updateObservation\", observation);\r\n            }\r\n            if (incomplete) {\r\n                let plan = this.deepCopy(this.plan);\r\n                let { item: incompleteItem } = plan;\r\n                if (!incompleteItem) {\r\n                    incompleteItem = localItem.item;\r\n                }\r\n                incompleteItem.sale_unit_price = incomplete.rest;\r\n                incompleteItem.percentage_igv = 18;\r\n                if (incomplete.start_date == incomplete.end_date) {\r\n                    incompleteItem.descriptionInternet = `Saldo pendiente de la instalación ${moment(\r\n                        incomplete.start_date\r\n                    ).format(\"DD/MM/YYYY\")}`;\r\n                } else {\r\n                    incompleteItem.descriptionInternet = `Saldo pendiente del periodo ${moment(\r\n                        incomplete.start_date\r\n                    ).format(\"DD/MM/YYYY\")} - ${moment(\r\n                        incomplete.end_date\r\n                    ).format(\"DD/MM/YYYY\")}`;\r\n                }\r\n                items.push(incompleteItem);\r\n\r\n                if (localItem) {\r\n                    this.setIncompleteObservation();\r\n                }\r\n            }\r\n\r\n            let form = {\r\n                operation_id: this.plan.operation_id,\r\n                months: this.monthsToPay\r\n            };\r\n\r\n            if (this.updatePlan) {\r\n                let perDay = this.newPlanCost / this.passedDays;\r\n                let toPay = perDay * this.leftDays;\r\n                form = {\r\n                    rest: toPay,\r\n                    operation_id: this.plan.operation_id,\r\n                    update: true,\r\n                    concepts: this.conceptsSelected,\r\n                    plan_variation_id: this.variationId\r\n                };\r\n\r\n                if (\r\n                    this.newPlanCost > 0 &&\r\n                    this.leftDays > 0 &&\r\n                    this.passedDays > 0\r\n                ) {\r\n                    let obs = this.observationChange();\r\n                    let perDay = this.newPlanCost / this.passedDays;\r\n                    let toPay = perDay * this.leftDays;\r\n                    obs += `SALDO RESTANTE NUEVO PLAN ${toPay}\\n`;\r\n                    this.$emit(\"updateObservation\", obs);\r\n                }\r\n            }\r\n\r\n            this.$emit(\"createFormRegister\", form);\r\n\r\n            this.$emit(\"updateItems\", items);\r\n        },\r\n\r\n        setIncompleteObservation() {\r\n            let observation = this.checkForIncomplete().toUpperCase();\r\n            if (this.updatePlan) {\r\n                observation += \"CAMBIO DE PLAN\\n\";\r\n            }\r\n            if (observation.length > 0) {\r\n                this.$emit(\"updateObservation\", observation);\r\n            }\r\n        },\r\n        async getTables() {\r\n            this.selectedMonths = [];\r\n            this.monthsToPay = [];\r\n            this.newPlanCost = 0;\r\n            this.leftDays = 0;\r\n            this.passedDays = 0;\r\n            this.variationId = null;\r\n            this.form = {};\r\n            this.variationConceptId = null;\r\n            this.conceptsSelected = [];\r\n            try {\r\n                const response = await this.$http(\"/internet/tables\");\r\n\r\n                const {\r\n                    plans,\r\n                    concepts,\r\n                    items,\r\n                    service_item,\r\n                    techs\r\n                } = response.data;\r\n                this.plans = plans ?? [];\r\n                this.concepts = concepts ?? [];\r\n                this.items = items ?? [];\r\n                this.techs = techs ?? [];\r\n                this.serviceItem = service_item;\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Internet/Resources/assets/js/view/pos/partials/service_form.vue","exports = module.exports = require(\"../../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.customcheck {\\r\\n    background-color: #67c23a !important;\\r\\n    border-color: #e1f3d8 !important;\\n}\\n.customcheck span {\\r\\n    background-color: #67c23a !important;\\r\\n    color: #ffffff !important;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/modules/Internet/Resources/assets/js/view/pos/partials/modules/Internet/Resources/assets/js/view/pos/partials/service_form.vue\"],\"names\":[],\"mappings\":\";AAyKA;IACA,qCAAA;IACA,iCAAA;CACA;AACA;IACA,qCAAA;IACA,0BAAA;CACA\",\"file\":\"service_form.vue\",\"sourcesContent\":[\"<template>\\r\\n    <div class=\\\"card bg-ligth\\\" v-loading=\\\"loading\\\">\\r\\n        <div class=\\\"row mt-2\\\">\\r\\n            <div class=\\\"col-12\\\">\\r\\n                <label class=\\\"label-control w-100\\\">Plan Actual</label>\\r\\n                <el-input :readonly=\\\"true\\\" :value=\\\"plan.name\\\"> </el-input>\\r\\n                <label v-if=\\\"paymentDay\\\" class=\\\"mt-2 label-control\\\"\\r\\n                    >Vencimiento:\\r\\n                    <strong>\\r\\n                        {{ `${paymentDay.split(\\\"/\\\")[0]} de cada mes` }}</strong\\r\\n                    ></label\\r\\n                >\\r\\n                <label\\r\\n                    v-if=\\\"currentPlan && currentPlan.days_extension != 0\\\"\\r\\n                    class=\\\"text-primary\\\"\\r\\n                    style=\\\"font-weight:bold\\\"\\r\\n                >\\r\\n                    / Prorroga:\\r\\n                    <strong> {{ currentPlan.days_extension }} días </strong>\\r\\n                </label>\\r\\n            </div>\\r\\n        </div>\\r\\n        <template v-if=\\\"updatePlan\\\">\\r\\n            <div class=\\\"row mt-2\\\">\\r\\n                <div class=\\\"col-md-6\\\">\\r\\n                    <label for=\\\"document type\\\">Plan nuevo</label>\\r\\n                    <el-select v-model=\\\"form.plan_id\\\" @change=\\\"changePrice\\\">\\r\\n                        <el-option\\r\\n                            v-for=\\\"(data, idx) in plans\\\"\\r\\n                            :key=\\\"idx\\\"\\r\\n                            :label=\\\"data.capacity\\\"\\r\\n                            :value=\\\"data.id\\\"\\r\\n                        >\\r\\n                        </el-option>\\r\\n                    </el-select>\\r\\n                </div>\\r\\n                <div class=\\\"col-md-6\\\">\\r\\n                    <label for=\\\"document type\\\">Precio</label>\\r\\n                    <el-select\\r\\n                        v-model=\\\"variationId\\\"\\r\\n                        @change=\\\"updateNewPlanCost\\\"\\r\\n                    >\\r\\n                        <el-option\\r\\n                            v-for=\\\"(data, idx) in planVariations\\\"\\r\\n                            :key=\\\"idx\\\"\\r\\n                            :label=\\\"`${data.description} S/.${data.price}`\\\"\\r\\n                            :value=\\\"data.id\\\"\\r\\n                        >\\r\\n                        </el-option>\\r\\n                    </el-select>\\r\\n                </div>\\r\\n            </div>\\r\\n            <div class=\\\"row mt-2\\\">\\r\\n                <div class=\\\"col-md-5\\\">\\r\\n                    <label for=\\\"document type\\\">Extras/Conceptos</label>\\r\\n                    <el-select v-model=\\\"concept.id\\\" @change=\\\"changeConcept\\\">\\r\\n                        <el-option\\r\\n                            v-for=\\\"(data, idx) in concepts\\\"\\r\\n                            :key=\\\"idx\\\"\\r\\n                            :label=\\\"data.description\\\"\\r\\n                            :value=\\\"data.id\\\"\\r\\n                        >\\r\\n                        </el-option>\\r\\n                    </el-select>\\r\\n                </div>\\r\\n\\r\\n                <div class=\\\"col-md-5\\\">\\r\\n                    <label for=\\\"document type\\\">Precio</label>\\r\\n                    <el-select v-model=\\\"variationConceptId\\\">\\r\\n                        <el-option\\r\\n                            v-for=\\\"(data, idx) in conceptVariations\\\"\\r\\n                            :key=\\\"idx\\\"\\r\\n                            :label=\\\"`${data.description} S/.${data.price}`\\\"\\r\\n                            :value=\\\"data.id\\\"\\r\\n                        >\\r\\n                        </el-option>\\r\\n                    </el-select>\\r\\n                </div>\\r\\n                <div class=\\\"col-md-2 mt-sm-2  mb-sm-1 d-flex align-items-end\\\">\\r\\n                    <el-button\\r\\n                        size=\\\"mini\\\"\\r\\n                        type=\\\"primary\\\"\\r\\n                        icon=\\\"el-icon-plus\\\"\\r\\n                        circle\\r\\n                        @click=\\\"addConcept\\\"\\r\\n                    ></el-button>\\r\\n                </div>\\r\\n                <div\\r\\n                    class=\\\"col-md-12 mt-1 table-responsive\\\"\\r\\n                    v-if=\\\"conceptsSelected.length != 0\\\"\\r\\n                >\\r\\n                    <table class=\\\"table  table-striped table-hover\\\">\\r\\n                        <thead>\\r\\n                            <tr>\\r\\n                                <th>#</th>\\r\\n                                <th>Extra</th>\\r\\n                                <th>Descripción</th>\\r\\n                                <th>Total</th>\\r\\n                                <th></th>\\r\\n                            </tr>\\r\\n                        </thead>\\r\\n                        <tbody>\\r\\n                            <tr\\r\\n                                v-for=\\\"(concept, idx) in conceptsSelected\\\"\\r\\n                                :key=\\\"idx\\\"\\r\\n                            >\\r\\n                                <td>{{ idx + 1 }}</td>\\r\\n                                <td>\\r\\n                                    {{ concept.generalConcept }}\\r\\n                                </td>\\r\\n                                <td>\\r\\n                                    {{ concept.description }}\\r\\n                                </td>\\r\\n                                <td>{{ concept.price }}</td>\\r\\n                                <td>\\r\\n                                    <el-button\\r\\n                                        @click=\\\"removeConcept(idx)\\\"\\r\\n                                        type=\\\"danger\\\"\\r\\n                                        icon=\\\"el-icon-delete\\\"\\r\\n                                        circle\\r\\n                                    ></el-button>\\r\\n                                </td>\\r\\n                            </tr>\\r\\n                        </tbody>\\r\\n                    </table>\\r\\n                </div>\\r\\n            </div>\\r\\n        </template>\\r\\n        <template v-else>\\r\\n            <div class=\\\"row mt-1 \\\">\\r\\n                <el-checkbox-group\\r\\n                    v-model=\\\"monthsToPay\\\"\\r\\n                    disabled\\r\\n                    class=\\\" d-flex flex-wrap justify-content-center\\\"\\r\\n                    @change=\\\"payMonth\\\"\\r\\n                >\\r\\n                    <el-checkbox-button\\r\\n                        class=\\\"mt-1\\\"\\r\\n                        :class=\\\"m.isNew ? 'customcheck' : ''\\\"\\r\\n                        v-for=\\\"(m, idx) in monthsPayed\\\"\\r\\n                        :key=\\\"idx\\\"\\r\\n                        :label=\\\"m.start_date\\\"\\r\\n                        >{{\\r\\n                            `${formatDate(m.start_date)} - ${formatDate(\\r\\n                                m.end_date\\r\\n                            )}`\\r\\n                        }}</el-checkbox-button\\r\\n                    >\\r\\n                </el-checkbox-group>\\r\\n            </div>\\r\\n            <div class=\\\" mt-1 d-flex justify-content-center\\\">\\r\\n                <el-button-group>\\r\\n                    <el-button\\r\\n                        type=\\\"primary\\\"\\r\\n                        icon=\\\"el-icon-circle-plus\\r\\n\\\"\\r\\n                        @click=\\\"addPayment\\\"\\r\\n                        >Agregar pago</el-button\\r\\n                    >\\r\\n                    <el-button type=\\\"danger\\\" @click=\\\"removePayment\\\"\\r\\n                        >Retirar Pago\\r\\n                        <i class=\\\"el-icon-delete el-icon-right\\\"></i\\r\\n                    ></el-button>\\r\\n                </el-button-group>\\r\\n            </div>\\r\\n        </template>\\r\\n    </div>\\r\\n</template>\\r\\n<style>\\r\\n.customcheck {\\r\\n    background-color: #67c23a !important;\\r\\n    border-color: #e1f3d8 !important;\\r\\n}\\r\\n.customcheck span {\\r\\n    background-color: #67c23a !important;\\r\\n    color: #ffffff !important;\\r\\n}\\r\\n</style>\\r\\n<script>\\r\\nimport moment from \\\"moment\\\";\\r\\nexport default {\\r\\n    props: [\\\"registerId\\\", \\\"plan\\\", \\\"updatePlan\\\"],\\r\\n\\r\\n    data() {\\r\\n        return {\\r\\n            payments: [],\\r\\n            passedDays: 0,\\r\\n            leftDays: 0,\\r\\n            conceptsSelected: [],\\r\\n            newPlanCost: 0,\\r\\n            concept: {},\\r\\n            planVariations: [],\\r\\n            conceptVariations: [],\\r\\n            variationId: null,\\r\\n            variationConceptId: null,\\r\\n            plans: [],\\r\\n            concepts: [],\\r\\n            items: [],\\r\\n            techs: [],\\r\\n            serviceItem: null,\\r\\n            dataReconnection: null,\\r\\n            originalMonthsPayed: [],\\r\\n            monthsPayed: [],\\r\\n            monthsToPay: [],\\r\\n            resource: \\\"registers\\\",\\r\\n            loading: false,\\r\\n            plans: [],\\r\\n            date: moment(),\\r\\n            paymentDay: null,\\r\\n            form: {},\\r\\n            currentPlan: null,\\r\\n            penalties: [],\\r\\n            limitDate: null,\\r\\n            selectedMonths: [],\\r\\n            months: [\\r\\n                { id: 1, label: \\\"Enero\\\", disabled: false },\\r\\n                { id: 2, label: \\\"Febrero\\\", disabled: false },\\r\\n                { id: 3, label: \\\"Marzo\\\", disabled: false },\\r\\n                { id: 4, label: \\\"Abril\\\", disabled: false },\\r\\n                { id: 5, label: \\\"Mayo\\\", disabled: false },\\r\\n                { id: 6, label: \\\"Junio\\\", disabled: false },\\r\\n                { id: 7, label: \\\"Julio\\\", disabled: false },\\r\\n                { id: 8, label: \\\"Agosto\\\", disabled: false },\\r\\n                { id: 9, label: \\\"Setiembre\\\", disabled: false },\\r\\n                { id: 10, label: \\\"Octubre\\\", disabled: false },\\r\\n                { id: 11, label: \\\"Noviembre\\\", disabled: false },\\r\\n                { id: 12, label: \\\"Diciembre\\\", disabled: false }\\r\\n            ]\\r\\n        };\\r\\n    },\\r\\n    async created() {\\r\\n        // await this.getTables();\\r\\n    },\\r\\n    methods: {\\r\\n        removeConcept(idx) {\\r\\n            this.conceptsSelected.splice(idx, 1);\\r\\n            this.updateNewPlanCost();\\r\\n        },\\r\\n        updateNewPlanCost() {\\r\\n            let [variation] = this.planVariations.filter(\\r\\n                p => p.id == this.variationId\\r\\n            );\\r\\n            this.newPlanCost = Number(variation.price);\\r\\n            if (this.conceptsSelected.length > 0) {\\r\\n                this.conceptsSelected.forEach(c => {\\r\\n                    this.newPlanCost += Number(c.price);\\r\\n                });\\r\\n            }\\r\\n\\r\\n            this.updateTotal();\\r\\n        },\\r\\n        observationChange() {\\r\\n            let [toPay] = this.calculateRestPlan();\\r\\n            let observation = `CAMBIO DE PLAN: ${toPay} RESTA PAGAR DEL PLAN ANTERIOR\\\\n`;\\r\\n            return observation;\\r\\n        },\\r\\n        changeConcept() {\\r\\n            let [concept] = this.concepts.filter(p => p.id == this.concept.id);\\r\\n\\r\\n            this.conceptVariations = concept.variations;\\r\\n\\r\\n            if (this.conceptVariations.length != 0) {\\r\\n                this.variationConceptId = this.conceptVariations[0].id;\\r\\n            } else {\\r\\n                this.variationConceptId = null;\\r\\n            }\\r\\n        },\\r\\n        addConcept() {\\r\\n            let [concept] = this.conceptVariations.filter(\\r\\n                cv => cv.id == this.variationConceptId\\r\\n            );\\r\\n\\r\\n            if (concept) {\\r\\n                let { concept_id } = concept;\\r\\n                let { description } = this.concepts.find(\\r\\n                    c => c.id == concept_id\\r\\n                );\\r\\n                this.conceptsSelected = this.conceptsSelected.filter(\\r\\n                    i => i.concept_id != concept.id\\r\\n                );\\r\\n                this.conceptsSelected.push({\\r\\n                    ...concept,\\r\\n                    generalConcept: description\\r\\n                });\\r\\n            }\\r\\n            this.updateNewPlanCost();\\r\\n        },\\r\\n        changePrice() {\\r\\n            let [plan] = this.plans.filter(p => p.id == this.form.plan_id);\\r\\n\\r\\n            this.form.plan_price = plan.default_price;\\r\\n            this.planVariations = plan.variations;\\r\\n\\r\\n            if (this.planVariations.length != 0) {\\r\\n                this.variationId = this.planVariations[0].id;\\r\\n            } else {\\r\\n                this.variationId = null;\\r\\n            }\\r\\n            if (this.variationId) {\\r\\n                this.updateNewPlanCost();\\r\\n            }\\r\\n            // this.calculateTotal();\\r\\n        },\\r\\n        addPayment() {\\r\\n            let end_date;\\r\\n            let amount;\\r\\n            let monthsNew = [];\\r\\n            if (this.monthsPayed.length == 0) {\\r\\n                end_date = this.plan.install_date;\\r\\n                amount = this.plan.total;\\r\\n            } else {\\r\\n                let lastPayment = this.monthsPayed[this.monthsPayed.length - 1];\\r\\n                monthsNew = this.monthsPayed.filter(m => m.isNew);\\r\\n                amount = lastPayment.amount;\\r\\n                if (this.dataReconnection && monthsNew.length == 0) {\\r\\n                    end_date = this.dataReconnection;\\r\\n                } else {\\r\\n                    end_date = lastPayment.end_date;\\r\\n                }\\r\\n            }\\r\\n\\r\\n            let newEndDate = moment(end_date).add(1, \\\"month\\\");\\r\\n\\r\\n            if (\\r\\n                monthsNew.length != 0 &&\\r\\n                this.originalMonthsPayed.length == 12\\r\\n            ) {\\r\\n                this.monthsPayed = this.originalMonthsPayed.slice(\\r\\n                    monthsNew.length + 1\\r\\n                );\\r\\n            }\\r\\n\\r\\n            this.monthsPayed = [\\r\\n                ...this.monthsPayed.filter(m => !m.isNew),\\r\\n                ...monthsNew\\r\\n            ];\\r\\n            this.monthsPayed = [\\r\\n                ...this.monthsPayed,\\r\\n                {\\r\\n                    amount,\\r\\n                    start_date: end_date,\\r\\n                    end_date: newEndDate,\\r\\n                    isNew: true\\r\\n                }\\r\\n            ];\\r\\n            this.monthsToPay.push(end_date);\\r\\n\\r\\n            this.checkMonths();\\r\\n            this.updateTotal();\\r\\n        },\\r\\n        changeInitialDate(date) {\\r\\n            this.dataReconnection = date;\\r\\n        },\\r\\n        checkForIncomplete() {\\r\\n            let observation = \\\"\\\";\\r\\n            let incomplete = this.originalMonthsPayed.find(\\r\\n                m => m.state == \\\"incomplete\\\"\\r\\n            );\\r\\n            if (this.originalMonthsPayed.length == 0 && incomplete == null) {\\r\\n                let payment = this.payments[this.payments.length - 1];\\r\\n                if (payment.type == \\\"incomplete\\\") {\\r\\n                    incomplete = {};\\r\\n                    incomplete.rest = payment.rest;\\r\\n                    incomplete.start_date = this.plan.install_date;\\r\\n                    incomplete.end_date = this.plan.install_date;\\r\\n                }\\r\\n            }\\r\\n            if (incomplete) {\\r\\n                if (incomplete.start_date == incomplete.end_date) {\\r\\n                    observation = `Saldo pendiente de la instalacion ${moment(\\r\\n                        incomplete.start_date\\r\\n                    ).format(\\\"DD/MM/YYYY\\\")}\\\\n`;\\r\\n                } else {\\r\\n                    observation = `Saldo pendiente del periodo ${moment(\\r\\n                        incomplete.start_date\\r\\n                    ).format(\\\"DD/MM/YYYY\\\")} - ${moment(\\r\\n                        incomplete.end_date\\r\\n                    ).format(\\\"DD/MM/YYYY\\\")}\\\\n`;\\r\\n                }\\r\\n            }\\r\\n            return observation;\\r\\n        },\\r\\n        checkMonths() {\\r\\n            let observation = this.checkForIncomplete();\\r\\n            if (this.monthsToPay.length == 1) {\\r\\n                let month = moment(this.monthsToPay[0]).format(\\\"DD/MM/YYYY\\\");\\r\\n                let nextMonth = moment(this.monthsToPay[0])\\r\\n                    .add(1, \\\"month\\\")\\r\\n                    .format(\\\"DD/MM/YYYY\\\");\\r\\n                observation += `Mensualidad de ${month} a ${nextMonth}`;\\r\\n            } else if (this.monthsToPay.length == 0) {\\r\\n                observation = \\\"\\\";\\r\\n            } else {\\r\\n                let month = moment(this.monthsToPay[0]).format(\\\"DD/MM/YYYY\\\");\\r\\n                let nextMonth = moment(\\r\\n                    this.monthsToPay[this.monthsToPay.length - 1]\\r\\n                )\\r\\n                    .add(1, \\\"month\\\")\\r\\n                    .format(\\\"DD/MM/YYYY\\\");\\r\\n                observation += `Mensualidad de ${month} a ${nextMonth}`;\\r\\n            }\\r\\n            observation = observation.toUpperCase();\\r\\n            this.$emit(\\\"updateObservation\\\", observation);\\r\\n        },\\r\\n        removePayment() {\\r\\n            let hasNew = this.monthsPayed.some(m => m.isNew);\\r\\n            if (hasNew) {\\r\\n                let lastNew = this.monthsPayed.pop();\\r\\n                let monthsNew = this.monthsPayed.filter(m => m.isNew);\\r\\n                if (\\r\\n                    monthsNew.length != 0 &&\\r\\n                    this.originalMonthsPayed.length == 12\\r\\n                ) {\\r\\n                    this.monthsPayed = this.originalMonthsPayed.slice(\\r\\n                        monthsNew.length\\r\\n                    );\\r\\n                }\\r\\n\\r\\n                this.monthsPayed = [\\r\\n                    ...this.monthsPayed.filter(m => !m.isNew),\\r\\n                    ...monthsNew\\r\\n                ];\\r\\n\\r\\n                this.monthsToPay = this.monthsToPay.filter(\\r\\n                    m => m != lastNew.start_date\\r\\n                );\\r\\n\\r\\n                this.checkMonths();\\r\\n                this.updateTotal();\\r\\n\\r\\n                if (monthsNew.length == 0) {\\r\\n                    this.setIncompleteObservation();\\r\\n                }\\r\\n            }\\r\\n        },\\r\\n        formatDate(date) {\\r\\n            return moment(date).format(\\\"DD/MM/YYYY\\\");\\r\\n        },\\r\\n\\r\\n        payMonth(x) {},\\r\\n        changePlan() {\\r\\n            this.paymentDay = null;\\r\\n            this.penalties = [];\\r\\n            this.currentPlan = null;\\r\\n            this.limitDate = null;\\r\\n            this.selectedMonths = [];\\r\\n            this.updateTotal();\\r\\n        },\\r\\n        //limit  es una fecha, con el mes y año actual, pero con el día del pago\\r\\n        //date es la fecha actual\\r\\n        //paymentday es solo el día\\r\\n        //\\r\\n        checkPenalty(date) {\\r\\n            let { total, penalty, days_extension } = this.currentPlan;\\r\\n\\r\\n            date = date.add(days_extension, \\\"days\\\");\\r\\n            if (this.date.isAfter(date.add())) {\\r\\n                if (penalty) {\\r\\n                    let { percentage, type } = penalty;\\r\\n                    percentage =\\r\\n                        type == \\\"percentage\\\"\\r\\n                            ? Number(percentage) / 100\\r\\n                            : Number(percentage);\\r\\n                    let totalPerDay =\\r\\n                        type == \\\"percentage\\\" ? total * percentage : percentage;\\r\\n                    let days = this.date.diff(date, \\\"days\\\");\\r\\n                    let month = date.get(\\\"month\\\") + 1;\\r\\n                    let nameMonth = this.months.find(m => m.id == month).label;\\r\\n                    this.penalties.push({\\r\\n                        id: month,\\r\\n                        days,\\r\\n                        label: nameMonth,\\r\\n                        penalty: days * totalPerDay\\r\\n                    });\\r\\n                }\\r\\n            }\\r\\n        },\\r\\n        selectMonth() {\\r\\n            this.updateTotal();\\r\\n        },\\r\\n        initForm() {\\r\\n            this.currentPlan = null;\\r\\n            this.penalties = [];\\r\\n            this.paymentDay = null;\\r\\n            this.form = {};\\r\\n            this.months = [\\r\\n                { id: 1, label: \\\"Enero\\\", disabled: false },\\r\\n                { id: 2, label: \\\"Febrero\\\", disabled: false },\\r\\n                { id: 3, label: \\\"Marzo\\\", disabled: false },\\r\\n                { id: 4, label: \\\"Abril\\\", disabled: false },\\r\\n                { id: 5, label: \\\"Mayo\\\", disabled: false },\\r\\n                { id: 6, label: \\\"Junio\\\", disabled: false },\\r\\n                { id: 7, label: \\\"Julio\\\", disabled: false },\\r\\n                { id: 8, label: \\\"Agosto\\\", disabled: false },\\r\\n                { id: 9, label: \\\"Setiembre\\\", disabled: false },\\r\\n                { id: 10, label: \\\"Octubre\\\", disabled: false },\\r\\n                { id: 11, label: \\\"Noviembre\\\", disabled: false },\\r\\n                { id: 12, label: \\\"Diciembre\\\", disabled: false }\\r\\n            ];\\r\\n        },\\r\\n        typeParent(type) {\\r\\n            let types = {\\r\\n                mother: \\\"Madre:\\\",\\r\\n                father: \\\"Padre:\\\",\\r\\n                attorney: \\\"Apoderado:\\\"\\r\\n            };\\r\\n\\r\\n            return types[type];\\r\\n        },\\r\\n        setPaymentMonths(months, payments = []) {\\r\\n            this.originalMonthsPayed = months.reverse();\\r\\n            this.payments = payments;\\r\\n            this.monthsPayed = [...this.originalMonthsPayed];\\r\\n        },\\r\\n        async setMonths() {\\r\\n            this.months = [\\r\\n                { id: 1, label: \\\"Enero\\\", disabled: false },\\r\\n                { id: 2, label: \\\"Febrero\\\", disabled: false },\\r\\n                { id: 3, label: \\\"Marzo\\\", disabled: false },\\r\\n                { id: 4, label: \\\"Abril\\\", disabled: false },\\r\\n                { id: 5, label: \\\"Mayo\\\", disabled: false },\\r\\n                { id: 6, label: \\\"Junio\\\", disabled: false },\\r\\n                { id: 7, label: \\\"Julio\\\", disabled: false },\\r\\n                { id: 8, label: \\\"Agosto\\\", disabled: false },\\r\\n                { id: 9, label: \\\"Setiembre\\\", disabled: false },\\r\\n                { id: 10, label: \\\"Octubre\\\", disabled: false },\\r\\n                { id: 11, label: \\\"Noviembre\\\", disabled: false },\\r\\n                { id: 12, label: \\\"Diciembre\\\", disabled: false }\\r\\n            ];\\r\\n            let today = moment();\\r\\n            let installDate = moment(this.plan.install_date);\\r\\n\\r\\n            if (today.year() == installDate.year()) {\\r\\n                let month = installDate.month() + 1;\\r\\n                this.months = this.months.map(m => {\\r\\n                    if (m.id < month) {\\r\\n                        m.disabled = true;\\r\\n                    }\\r\\n                    return m;\\r\\n                });\\r\\n            }\\r\\n            let payments = this.plan.payments;\\r\\n            let paidmonths = [];\\r\\n            if (payments) {\\r\\n                for (let i = 0; i < payments.length; i++) {\\r\\n                    const payment = payments[i];\\r\\n                    if (payment.type == \\\"complete\\\") {\\r\\n                        paidmonths = [\\r\\n                            ...paidmonths,\\r\\n                            ...payment.months\\r\\n                                .filter(m => {\\r\\n                                    let dt = moment(m.year);\\r\\n                                    if (today.year() == dt.year()) {\\r\\n                                        return m;\\r\\n                                    }\\r\\n                                })\\r\\n                                .map(m => m.month)\\r\\n                        ];\\r\\n                    } else {\\r\\n                    }\\r\\n                }\\r\\n            }\\r\\n\\r\\n            for (let m of paidmonths) {\\r\\n                let month = this.months.find(mth => mth.id == m);\\r\\n                if (month) {\\r\\n                    month.disabled = true;\\r\\n                }\\r\\n            }\\r\\n        },\\r\\n        deepCopy(obj) {\\r\\n            if (obj === null || typeof obj !== \\\"object\\\") {\\r\\n                return obj;\\r\\n            }\\r\\n\\r\\n            let copy;\\r\\n\\r\\n            if (obj instanceof Array) {\\r\\n                copy = [];\\r\\n                for (let i = 0; i < obj.length; i++) {\\r\\n                    copy[i] = this.deepCopy(obj[i]);\\r\\n                }\\r\\n            } else {\\r\\n                copy = {};\\r\\n                for (let key in obj) {\\r\\n                    if (obj.hasOwnProperty(key)) {\\r\\n                        copy[key] = this.deepCopy(obj[key]);\\r\\n                    }\\r\\n                }\\r\\n            }\\r\\n\\r\\n            return copy;\\r\\n        },\\r\\n        calculateRestPlan() {\\r\\n            let total = this.plan.total;\\r\\n            let month = this.originalMonthsPayed[\\r\\n                this.originalMonthsPayed.length - 1\\r\\n            ];\\r\\n            let today = moment().startOf(\\\"day\\\");\\r\\n            let endDate = moment(month.end_date).startOf(\\\"day\\\");\\r\\n            let startDate = moment(month.start_date).startOf(\\\"day\\\");\\r\\n            let passed_days = endDate.diff(startDate, \\\"days\\\");\\r\\n            let left_days = endDate.diff(today, \\\"days\\\"); // devuelve 1\\r\\n\\r\\n            let totalPerDay = total / passed_days;\\r\\n            let toPay = totalPerDay * (passed_days - left_days);\\r\\n\\r\\n            return [toPay, left_days, passed_days];\\r\\n        },\\r\\n        async updateTotal(localItem) {\\r\\n            let items = [];\\r\\n\\r\\n            if (this.monthsToPay.length > 0) {\\r\\n                let plan = this.deepCopy(this.plan);\\r\\n                let { item, name, total } = plan;\\r\\n                item.sale_unit_price = total * this.monthsToPay.length;\\r\\n                item.percentage_igv = 18;\\r\\n                item.descriptionInternet = name;\\r\\n                items.push(item);\\r\\n            }\\r\\n            let incomplete = this.originalMonthsPayed.find(\\r\\n                m => m.state == \\\"incomplete\\\"\\r\\n            );\\r\\n            if (this.originalMonthsPayed.length == 0 && incomplete == null) {\\r\\n                let payment = this.payments[this.payments.length - 1];\\r\\n                if (payment.type == \\\"incomplete\\\") {\\r\\n                    incomplete = {};\\r\\n                    incomplete.rest = payment.rest;\\r\\n                    incomplete.start_date = this.plan.install_date;\\r\\n                    incomplete.end_date = this.plan.install_date;\\r\\n                }\\r\\n            }\\r\\n            if (this.updatePlan) {\\r\\n                let [toPay, left_days, passed_days] = this.calculateRestPlan();\\r\\n                this.leftDays = left_days;\\r\\n                this.passedDays = passed_days;\\r\\n                let plan = this.deepCopy(this.plan);\\r\\n                let { item, name } = plan;\\r\\n                item.sale_unit_price = toPay;\\r\\n                item.percentage_igv = 18;\\r\\n                item.descriptionInternet = name + \\\" (Saldo plan anterior)\\\";\\r\\n                items.push(item);\\r\\n                let observation = `CAMBIO DE PLAN: ${toPay} RESTA PAGAR DEL PLAN ANTERIOR`;\\r\\n                this.$emit(\\\"updateObservation\\\", observation);\\r\\n            }\\r\\n            if (incomplete) {\\r\\n                let plan = this.deepCopy(this.plan);\\r\\n                let { item: incompleteItem } = plan;\\r\\n                if (!incompleteItem) {\\r\\n                    incompleteItem = localItem.item;\\r\\n                }\\r\\n                incompleteItem.sale_unit_price = incomplete.rest;\\r\\n                incompleteItem.percentage_igv = 18;\\r\\n                if (incomplete.start_date == incomplete.end_date) {\\r\\n                    incompleteItem.descriptionInternet = `Saldo pendiente de la instalación ${moment(\\r\\n                        incomplete.start_date\\r\\n                    ).format(\\\"DD/MM/YYYY\\\")}`;\\r\\n                } else {\\r\\n                    incompleteItem.descriptionInternet = `Saldo pendiente del periodo ${moment(\\r\\n          